def search(query, df, bm25, model, index, top_k=10):
    tokens = _bm25_tokenize(query)
    query_vec = model.encode([query]).astype("float32")

    # Retrieval
    bm25_scores = bm25.get_scores(tokens)
    top_bm25_idx = np.argpartition(bm25_scores, -100)[-100:]

    dists, idxs = index.search(query_vec, 100)
    idxs = idxs[0]
    dists = dists[0]

    # Unique Candidates
    candidates = np.unique(np.concatenate([top_bm25_idx, idxs]))

    # RRF scoring
    rrf_scores = np.zeros(len(candidates))

    # BM25 RRF
    bm25_map = {idx: i for i, idx in enumerate(np.argsort(bm25_scores[candidates])[::-1])}
    for i, c_idx in enumerate(candidates):
        if c_idx in bm25_map:
            rrf_scores[i] += 1.0 / (60 + bm25_map[c_idx])

    # Semantic RRF
    sem_map = {idx: i for i, idx in enumerate(idxs)}
    for i, c_idx in enumerate(candidates):
        if c_idx in sem_map:
            rrf_scores[i] += 1.0 / (60 + sem_map[c_idx])

    # Genre Boosting
    target_genres = [t for t in tokens if t in ["drama", "comedy", "thriller", "action", "sci-fi", "horror", "romance", "documentary"]]
    if target_genres:
        for i, c_idx in enumerate(candidates):
            g = str(df.iloc[c_idx]['genres']).lower()
