                rrf_scores[i] *= 1.2

    # Popularity Boost
    pop = np.log1p(df.iloc[candidates]['vote_count'])
    rrf_scores += (pop / pop.max()) * 0.05

    # Result sorting
    best_idx = candidates[np.argsort(rrf_scores)[::-1][:top_k]]
    return df.iloc[best_idx].to_dict("records")

import numpy as np
from rank_bm25 import BM25Okapi
import re

def _bm25_tokenize(text):
    return re.findall(r'\b\w\w+\b', text.lower())

def search(query, df, bm25, model, index, top_k=10):
    tokens = _bm25_tokenize(query)
    bm25_scores = bm25.get_scores(tokens)

    # Title-boosted BM25: increment score for matches in title
    titles = df['title'].str.lower().values
    for i, title in enumerate(titles):
        for token in tokens:
            if token in title:
                bm25_scores[i] += 1.5

    pool_size = 500
    idx_b = np.argpartition(bm25_scores, -pool_size)[-pool_size:]

    query_vec = model.encode([query]).astype("float32")
    dists, idx_s = index.search(query_vec, pool_size)

    # Candidate aggregation with RRF
    candidates = np.unique(np.concatenate([idx_b, idx_s[0]]))
    rrf_scores = np.zeros(len(candidates))

    # RRF maps
    rank_b = {idx: r for r, idx in enumerate(idx_b[np.argsort(bm25_scores[idx_b])][::-1])}
    rank_s = {idx: r for r, idx in enumerate(idx_s[0])}

    for i, c in enumerate(candidates):
        r1 = rank_b.get(c, pool_size)
        r2 = rank_s.get(c, pool_size)
        rrf_scores[i] = 1.0 / (60.0 + r1) + 1.0 / (60.0 + r2)

    # Genre affinity boost
    query_genres = [g.lower() for g in tokens if g in ['action', 'comedy', 'drama', 'horror', 'sci-fi', 'thriller', 'romance']]
    if query_genres:
        for i, c in enumerate(candidates):
            movie_genres = df['genres'].iloc[c].lower()
            if any(g in movie_genres for g in query_genres):
                rrf_scores[i] *= 1.5

    # Popularity boost (dampened)
    pop = np.log1p(df['vote_count'].iloc[candidates].values)
    final_scores = rrf_scores * (1.0 + 0.1 * pop)

    top_indices = candidates[np.argsort(final_scores)[-top_k:][::-1]]
    return df.iloc[top_indices].to_dict("records")

